import requests
import os


class Tools:
    @staticmethod
    def run(term: str = None, pmid: str = None, retmax: int = 10) -> dict:
        """
        Search PubMed or fetch by PMID.
        Use term for search, pmid for single record.
        Returns titles, abstracts, authors, PMC links, etc.
        """
        api_key = os.environ.get("NCBI_API_KEY")
        base_url = "https://eutils.ncbi.nlm.nih.gov/entrez/eutils"

        if term:
            # Search
            url = f"{base_url}/esearch.fcgi"
            params = {
                "db": "pubmed",
                "term": term,
                "retmax": retmax,
                "retmode": "json",
                "api_key": api_key,
            }
            r = requests.get(url, params=params, timeout=10)
            r.raise_for_status()
            ids = r.json()["esearchresult"]["idlist"]
            if not ids:
                return {"results": []}

            # Fetch summaries
            url = f"{base_url}/esummary.fcgi"
            params = {
                "db": "pubmed",
                "id": ",".join(ids),
                "retmode": "json",
                "api_key": api_key,
            }
            r = requests.get(url, params=params, timeout=10)
            r.raise_for_status()
            return r.json()

        elif pmid:
            url = f"{base_url}/efetch.fcgi"
            params = {
                "db": "pubmed",
                "id": pmid,
                "retmode": "xml",
                "rettype": "abstract",
                "api_key": api_key,
            }
            r = requests.get(url, params=params, timeout=10)
            return {"xml": r.text}  # parse XML if needed in follow-up

        return {"error": "Provide term or pmid"}
